/**
	 * Get the Sift user ID to use for the current request.
	 *
	 * @return string The Sift user ID to use for the current request. Empty string if we couldn't determine one.
	 */
function get_sift_user_id(): string {
		$user_id = '';

		if ( ! is_user_logged_in() ) {
			return $user_id;
		}

		if ( is_admin() ) {
			// In the WP admin we deal with merchant accounts, not customers.
			$user_id = $this->account->get_stripe_account_id() ?? '';
		} else {
			$customer_id = $this->customer_service->get_customer_id_by_user_id( get_current_user_id() );
			if ( isset( $customer_id ) ) {
				$user_id = $customer_id;
			}
		}

		return $user_id;
	}

/**
	 * Register file as attachment to the Media page.
	 *
	 * @param string $log_path log file path.
	 * @return void
	 */
function register_file_as_media_attachment( $log_path ) {
		// Check the type of file.
		$log_mimes = array( 'txt' => 'text/plain' );
		$filetype  = wp_check_filetype( basename( $log_path ), self::apply_filters( 'ocdi/file_mimes', $log_mimes ) );

		// Prepare an array of post data for the attachment.
		$attachment = array(
			'guid'           => self::get_log_url( $log_path ),
			'post_mime_type' => $filetype['type'],
			'post_title'     => self::apply_filters( 'ocdi/attachment_prefix', esc_html__( 'One Click Demo Import - ', 'one-click-demo-import' ) ) . preg_replace( '/\.[^.]+$/', '', basename( $log_path ) ),
			'post_content'   => '',
			'post_status'    => 'inherit',
		);

		// Insert the file as attachment in Media page.
		$attach_id = wp_insert_attachment( $attachment, $log_path );
	}

