					array(
						'label'        => __( 'Select JSON File', 'acf' ),
						'type'         => 'file',
						'name'         => 'acf_import_file',
						'value'        => false,
						'uploader'     => 'basic',
						'mime_types'   => 'application/json,application/x-json,application/x-javascript,text/javascript,text/x-javascript,text/json',
						'instructions' => __( 'Import JSON containing field groups, post types, or taxonomies (trusted sources only)', 'acf' ),
					)
				);

				?>
			</div>
			<p class="acf-submit">
				<button type="submit" class="acf-btn" name="import_type" value="json">
					<?php esc_html_e( 'Import JSON', 'acf' ); ?>
				</button>
			</p>

			<?php
			if ( is_plugin_active( 'custom-post-type-ui/custom-post-type-ui.php' ) && acf_get_setting( 'enable_post_types' ) ) {
				$cptui_post_types  = get_option( 'cptui_post_types' );
				$cptui_taxonomies  = get_option( 'cptui_taxonomies' );
				$choices           = array();
				$overwrite_warning = false;

				if ( $cptui_post_types ) {
					$choices['post_types'] = __( 'Post Types', 'acf' );
					$existing_post_types   = acf_get_acf_post_types();

					foreach ( $existing_post_types as $existing_post_type ) {
						if ( isset( $cptui_post_types[ $existing_post_type['post_type'] ] ) ) {
							$overwrite_warning = true;
						}
					}
				}

				if ( $cptui_taxonomies ) {
					$choices['taxonomies'] = __( 'Taxonomies', 'acf' );

					if ( ! $overwrite_warning ) {
						$existing_taxonomies = acf_get_acf_taxonomies();
						foreach ( $existing_taxonomies as $existing_taxonomy ) {
							if ( isset( $cptui_taxonomies[ $existing_taxonomy['taxonomy'] ] ) ) {
								$overwrite_warning = true;
							}
						}
					}
				}

				if ( ! empty( $choices ) ) :
					?>
					<div class="acf-fields import-cptui">
						<?php
						acf_render_field_wrap(
							array(
								'label'   => __( 'Import from Custom Post Type UI', 'acf' ),
								'type'    => 'checkbox',
								'name'    => 'acf_import_cptui',
								'choices' => $choices,
								'toggle'  => true,
							)
						);
						?>
					</div>
					<?php
					if ( $overwrite_warning ) {
						echo '<p class="acf-inline-notice notice notice-info">' . esc_html__( 'Importing a Post Type or Taxonomy with the same key as one that already exists will overwrite the settings for the existing Post Type or Taxonomy with those of the import.', 'acf' ) . '</p>';
					}
					?>
					<p class="acf-submit">
						<button type="submit" class="acf-btn" name="import_type" value="cptui">
							<?php esc_html_e( 'Import from Custom Post Type UI', 'acf' ); ?>
						</button>
					</p>
					<?php
				endif;
			}
			?>
		</div>
			<?php
		}

/**
	 * Get the connected user's subscriptions.
	 *
	 * @return array
	 *
	 * phpcs:ignore Squiz.Commenting.FunctionCommentThrowTag.Missing -- As we wrap the throw in a try/catch.
	 */
function get_subscriptions() {
		$cache_key = '_woocommerce_helper_subscriptions';
		$data      = get_transient( $cache_key );
		if ( false !== $data ) {
			if ( is_array( $data ) ) {
				return $data;
			}
			// Cached data is corrupted, delete and fetch fresh.
			delete_transient( $cache_key );
		}

		try {
			$request_uri = wp_unslash( $_SERVER['REQUEST_URI'] ?? '' ); // phpcs:ignore WordPress.Security.ValidatedSanitizedInput.InputNotSanitized
			$source      = '';
			if ( false !== stripos( $request_uri, 'wc/v3/marketplace/refresh' ) ) :
				$source = 'refresh-button';
			elseif ( false !== stripos( $request_uri, 'my-subscriptions' ) ) :
				$source = 'my-subscriptions';
			elseif ( false !== stripos( $request_uri, 'plugins.php' ) ) :
				$source = 'plugins';
			elseif ( false !== stripos( $request_uri, 'wc-admin' ) ) :
				$source = 'inbox-notes';
			elseif ( false !== stripos( $request_uri, 'admin-ajax.php' ) ) :
				$source = 'heartbeat-api';
			elseif ( false !== stripos( $request_uri, 'wc/v3/marketplace' ) ) :
				$source = 'wccom-site-installer';
			elseif ( defined( 'WP_CLI' ) && WP_CLI ) :
				$source = 'wc-cli';
			endif;

			// Obtain the connected user info.
			$request = WC_Helper_API::get(
				'subscriptions',
				array(
					'authenticated' => true,
					'query_string'  => '' !== $source ? esc_url( '?source=' . $source ) : '',
				)
			);

			if ( is_wp_error( $request ) ) {
				set_transient( $cache_key, array(), 15 * MINUTE_IN_SECONDS );

				throw new Exception( $request->get_error_message(), (int) $request->get_error_data() );
			}

			$code = wp_remote_retrieve_response_code( $request );
			if ( 200 !== $code ) {
				set_transient( $cache_key, array(), 15 * MINUTE_IN_SECONDS );
				throw new Exception( self::get_message_for_response_code( $code ), $code );
			}

			$data = json_decode( wp_remote_retrieve_body( $request ), true );
			if ( ! is_array( $data ) ) {
				set_transient( $cache_key, array(), 15 * MINUTE_IN_SECONDS );
				throw new Exception( __( 'WooCommerce.com API returned an invalid response.', 'woocommerce' ), 422 );
			}

			set_transient( $cache_key, $data, 3 * HOUR_IN_SECONDS );

			self::remove_api_error_notice();
			return $data;
		} catch ( Exception $e ) {
			if ( $e->getCode() < 404 ) {
				self::remove_api_error_notice();
			} else {
				self::log( 'Error getting subscriptions: ' . $e->getMessage(), 'error' );
				self::add_api_error_notice();
			}
		}

		return array();
	}

